const user = { name: 'Alice', age: 30, city: 'Paris' };

// Old way — repetitive
const name = user.name;
const age  = user.age;
const city = user.city;

const product = {
  id: 42,
  title: 'Laptop',
  price: 999,
  inStock: true
};

// Extract only the properties you need
const { title, price } = product;

console.log(title);  // 'Laptop'
console.log(price);  // 999
// id and inStock are NOT extracted — they stay on the object

const response = { data: [1, 2, 3], status: 200 };

// Rename 'data' to 'items', and 'status' to 'httpCode'
const { data: items, status: httpCode } = response;

console.log(items);     // [1, 2, 3]
console.log(httpCode);  // 200
// 'data' and 'status' are NOT created as variables here

const settings = { theme: 'dark' };

const { theme, fontSize = 16, language = 'en' } = settings;

console.log(theme);     // 'dark'  — from the object
console.log(fontSize);  // 16     — default used (not in object)
console.log(language);  // 'en'   — default used (not in object)

const config = {};

// Rename 'timeout' to 'delay', with a default of 3000
const { timeout: delay = 3000 } = config;

console.log(delay);  // 3000

const user = {
  id: 1,
  name: 'Alice',
  address: {
    city: 'Paris',
    country: 'France'
  }
};

// Extract 'name' and the nested 'city' and 'country'
const { name, address: { city, country } } = user;

console.log(name);     // 'Alice'
console.log(city);     // 'Paris'
console.log(country);  // 'France'
// 'address' is NOT a variable — it is only used as a lookup key

const { title, price, ...rest } = {
  title: 'Headphones',
  price: 79,
  brand: 'Sony',
  color: 'black',
  weight: '250g'
};

console.log(title);  // 'Headphones'
console.log(price);  // 79
console.log(rest);   // { brand: 'Sony', color: 'black', weight: '250g' }

// Without destructuring
function greet(user) {
  return `Hello, ${user.name}! You are ${user.age} years old.`;
}

// With parameter destructuring
function greet({ name, age }) {
  return `Hello, ${name}! You are ${age} years old.`;
}

greet({ name: 'Alice', age: 30 }); // 'Hello, Alice! You are 30 years old.'

// Without destructuring — verbose, props. everywhere
function Button(props) {
  return (
    <button onClick={props.onClick} disabled={props.disabled}>
      {props.label}
    </button>
  );
}

// With parameter destructuring — clean and readable
function Button({ label, onClick, disabled = false }) {
  return (
    <button onClick={onClick} disabled={disabled}>
      {label}
    </button>
  );
}

function UserCard({ user, onEdit, onDelete, compact = false }) {
  const {
    id,
    name,
    email,
    role,
    avatar,
    address: { city, country } = {}
  } = user;

  return (
    <div className={compact ? 'card card--compact' : 'card'}>
      <img src={avatar} alt={name} />
      <h2>{name}</h2>
      <p>{email}</p>
      <span className="badge">{role}</span>
      {!compact && <p>{city}, {country}</p>}
      <button onClick={() => onEdit(id)}>Edit</button>
      <button onClick={() => onDelete(id)}>Delete</button>
    </div>
  );
}

const obj = { x: 10 };

// Renaming:       { key: variableName }
const { x: myX } = obj;          // myX = 10

// Default value:  { key = fallback }
const { y = 5 } = obj;           // y = 5 (property missing)

// Both combined:  { key: variableName = fallback }
const { x: myX2 = 99 } = obj;    // myX2 = 10 (property exists, default not used)
const { z: myZ = 99 } = obj;     // myZ = 99 (property missing, default used)

const user = { name: 'Alice' };

const { name } = user;  // ✅ extracts the 'name' property — name is 'Alice'
const name2 = user;     // ❌ assigns the whole object — name2 is { name: 'Alice' }
